function translatePage(e){const t=window.location.href,n=`https://translate.google.com/translate?sl=zh-TW&tl=${e}&u=${encodeURIComponent(t)}`;window.open(n,"_blank")}document.addEventListener("DOMContentLoaded",function(){const e=document.querySelectorAll("[data-translate-to]");e.forEach(e=>{e.addEventListener("click",function(e){e.preventDefault();const t=this.getAttribute("data-translate-to");translatePage(t)})})})